    @WebMethod(operationName = "addEmployee")
    public ServiceResponse addEmployee(
            @WebParam(name = "employeeId") int employeeId,
            @WebParam(name = "firstName") String firstName,
            @WebParam(name = "lastName") String lastName,
            @WebParam(name = "department") String department,
            @WebParam(name = "position") String position,
            @WebParam(name = "salary") double salary,
            @WebParam(name = "hireDate") String hireDate) {

        if (employeeDatabase.containsKey(employeeId)) {
            return new ServiceResponse(false,
                    "Employee with ID " + employeeId + " already exists.", "ERR_DUPLICATE_ID");
        }

        if (firstName == null || firstName.trim().isEmpty() ||
            lastName == null || lastName.trim().isEmpty()) {
            return new ServiceResponse(false,
                    "First name and last name are required.", "ERR_MISSING_FIELDS");
        }

        if (salary < 0) {
            return new ServiceResponse(false,
                    "Salary cannot be negative.", "ERR_INVALID_SALARY");
        }

        Employee employee = new Employee(employeeId, firstName.trim(), lastName.trim(),
                department, position, salary, hireDate);
        employeeDatabase.put(employeeId, employee);

        System.out.println("[HR Service] Added new employee: " + employee);

        return new ServiceResponse(true,
                "Employee " + firstName + " " + lastName + " added successfully with ID " + employeeId);
    }

