    @WebMethod(operationName = "getDepartmentSalaryReport")
    public String getDepartmentSalaryReport(@WebParam(name = "department") String department) {
        StringBuilder sb = new StringBuilder();
        sb.append("=== Salary Report for ").append(department).append(" ===\n");

        double totalSalary = 0;
        int count = 0;
        double minSalary = Double.MAX_VALUE;
        double maxSalary = Double.MIN_VALUE;

        for (Employee emp : employeeDatabase.values()) {
            if (emp.getDepartment().equalsIgnoreCase(department) && "ACTIVE".equals(emp.getStatus())) {
                sb.append(emp.getFirstName()).append(" ").append(emp.getLastName())
                  .append(" (").append(emp.getPosition()).append("): $")
                  .append(String.format("%.2f", emp.getSalary())).append("\n");
                totalSalary += emp.getSalary();
                minSalary = Math.min(minSalary, emp.getSalary());
                maxSalary = Math.max(maxSalary, emp.getSalary());
                count++;
            }
        }

        if (count == 0) {
            return "No active employees found in department: " + department;
        }

        sb.append("---\n");
        sb.append("Total Employees: ").append(count).append("\n");
        sb.append("Total Salary Budget: $").append(String.format("%.2f", totalSalary)).append("\n");
        sb.append("Average Salary: $").append(String.format("%.2f", totalSalary / count)).append("\n");
        sb.append("Min Salary: $").append(String.format("%.2f", minSalary)).append("\n");
        sb.append("Max Salary: $").append(String.format("%.2f", maxSalary)).append("\n");

        return sb.toString();
    }

    // ==================== Performance Review Operations ====================

    @WebMethod(operationName = "submitPerformanceReview")
    public ServiceResponse submitPerformanceReview(
            @WebParam(name = "employeeId") int employeeId,
            @WebParam(name = "reviewerName") String reviewerName,
            @WebParam(name = "rating") int rating,
            @WebParam(name = "comments") String comments,
            @WebParam(name = "reviewPeriod") String reviewPeriod,
            @WebParam(name = "strengths") String strengths,
            @WebParam(name = "areasForImprovement") String areasForImprovement,
            @WebParam(name = "promotionRecommended") boolean promotionRecommended) {

        Employee employee = employeeDatabase.get(employeeId);

        if (employee == null) {
            return new ServiceResponse(false,
                    "Employee with ID " + employeeId + " not found.", "ERR_NOT_FOUND");
        }

        if (!"ACTIVE".equals(employee.getStatus())) {
            return new ServiceResponse(false,
                    "Cannot submit review for non-active employee.", "ERR_INACTIVE_EMPLOYEE");
        }

        if (rating < 1 || rating > 5) {
            return new ServiceResponse(false,
                    "Rating must be between 1 and 5.", "ERR_INVALID_RATING");
        }

        if (reviewerName == null || reviewerName.trim().isEmpty()) {
            return new ServiceResponse(false,
                    "Reviewer name is required.", "ERR_MISSING_REVIEWER");
        }

        if (comments == null || comments.trim().isEmpty()) {
            return new ServiceResponse(false,
                    "Review comments are required.", "ERR_MISSING_COMMENTS");
        }

        int reviewId = ++reviewIdCounter;
        String reviewDate = new SimpleDateFormat("yyyy-MM-dd").format(new Date());

        PerformanceReview review = new PerformanceReview(
                reviewId, employeeId, reviewDate, reviewerName.trim(),
                rating, comments.trim(), reviewPeriod,
                strengths != null ? strengths.trim() : "",
                areasForImprovement != null ? areasForImprovement.trim() : "",
                promotionRecommended);

        employee.getPerformanceReviews().add(review);

        String ratingLabel;
        switch (rating) {
            case 1: ratingLabel = "Needs Improvement"; break;
            case 2: ratingLabel = "Below Expectations"; break;
            case 3: ratingLabel = "Meets Expectations"; break;
            case 4: ratingLabel = "Exceeds Expectations"; break;
            case 5: ratingLabel = "Outstanding"; break;
            default: ratingLabel = "Unknown";
        }

        System.out.println("[HR Service] Performance review submitted - Employee: " +
                employeeId + ", Rating: " + rating + " (" + ratingLabel + "), Reviewer: " + reviewerName);

        if (promotionRecommended) {
            System.out.println("[HR Service] NOTICE: Employee " + employeeId +
                    " has been recommended for promotion by " + reviewerName);
        }

        return new ServiceResponse(true,
                "Performance review (ID: " + reviewId + ") submitted successfully for " +
                employee.getFirstName() + " " + employee.getLastName() +
                ". Rating: " + rating + "/5 (" + ratingLabel + ")" +
                (promotionRecommended ? " - PROMOTION RECOMMENDED" : ""));
    }

    @WebMethod(operationName = "getPerformanceReviews")
    public String getPerformanceReviews(@WebParam(name = "employeeId") int employeeId) {
        Employee employee = employeeDatabase.get(employeeId);

        if (employee == null) {
            return "ERROR: Employee with ID " + employeeId + " not found.";
        }

        List<PerformanceReview> reviews = employee.getPerformanceReviews();

        if (reviews.isEmpty()) {
            return "No performance reviews found for employee " + employeeId;
        }

        StringBuilder sb = new StringBuilder();
        sb.append("=== Performance Reviews for ").append(employee.getFirstName())
          .append(" ").append(employee.getLastName()).append(" ===\n");

        double totalRating = 0;
        for (PerformanceReview review : reviews) {
            sb.append("Review ID: ").append(review.getReviewId()).append("\n");
            sb.append("  Date: ").append(review.getReviewDate()).append("\n");
            sb.append("  Period: ").append(review.getReviewPeriod()).append("\n");
            sb.append("  Reviewer: ").append(review.getReviewerName()).append("\n");
            sb.append("  Rating: ").append(review.getRating()).append("/5\n");
            sb.append("  Comments: ").append(review.getComments()).append("\n");
            if (!review.getStrengths().isEmpty()) {
                sb.append("  Strengths: ").append(review.getStrengths()).append("\n");
            }
            if (!review.getAreasForImprovement().isEmpty()) {
                sb.append("  Areas for Improvement: ").append(review.getAreasForImprovement()).append("\n");
            }
            sb.append("  Promotion Recommended: ").append(review.isPromotionRecommended() ? "Yes" : "No").append("\n");
            sb.append("---\n");
            totalRating += review.getRating();
        }

        sb.append("Average Rating: ").append(String.format("%.1f", totalRating / reviews.size())).append("/5\n");
        sb.append("Total Reviews: ").append(reviews.size());

        return sb.toString();
    }

    @WebMethod(operationName = "getAveragePerformanceRating")
    public String getAveragePerformanceRating(@WebParam(name = "employeeId") int employeeId) {
        Employee employee = employeeDatabase.get(employeeId);

        if (employee == null) {
            return "ERROR: Employee not found.";
        }

        List<PerformanceReview> reviews = employee.getPerformanceReviews();
        if (reviews.isEmpty()) {
            return "No performance reviews available for this employee.";
        }

        double total = 0;
        for (PerformanceReview review : reviews) {
            total += review.getRating();
        }
        double average = total / reviews.size();

        return "Employee " + employee.getFirstName() + " " + employee.getLastName() +
               " - Average Performance Rating: " + String.format("%.2f", average) +
               "/5 (based on " + reviews.size() + " reviews)";
    }

    @WebMethod(operationName = "getPromotionCandidates")
    public String getPromotionCandidates() {
        StringBuilder sb = new StringBuilder();
        sb.append("=== Promotion Candidates ===\n");

        int count = 0;
        for (Employee emp : employeeDatabase.values()) {
            if (!"ACTIVE".equals(emp.getStatus())) continue;

            for (PerformanceReview review : emp.getPerformanceReviews()) {
                if (review.isPromotionRecommended()) {
                    sb.append("Employee: ").append(emp.getFirstName()).append(" ").append(emp.getLastName())
                      .append(" (ID: ").append(emp.getEmployeeId()).append(")")
                      .append(" | Dept: ").append(emp.getDepartment())
                      .append(" | Position: ").append(emp.getPosition())
                      .append(" | Recommended by: ").append(review.getReviewerName())
                      .append(" | Rating: ").append(review.getRating()).append("/5\n");
                    count++;
                    break;
                }
            }
        }

        if (count == 0) {
            return "No promotion candidates found.";
        }

        sb.append("Total Candidates: ").append(count);
        return sb.toString();
    }

    // ==================== Termination Operations ====================

    @WebMethod(operationName = "terminateEmployee")
    public ServiceResponse terminateEmployee(
            @WebParam(name = "employeeId") int employeeId,
            @WebParam(name = "reason") String reason,
            @WebParam(name = "terminationType") String terminationType,
            @WebParam(name = "terminationDate") String terminationDate,
            @WebParam(name = "processedBy") String processedBy,
            @WebParam(name = "eligibleForRehire") boolean eligibleForRehire,
            @WebParam(name = "exitInterviewNotes") String exitInterviewNotes) {

        Employee employee = employeeDatabase.get(employeeId);

        if (employee == null) {
            return new ServiceResponse(false,
                    "Employee with ID " + employeeId + " not found.", "ERR_NOT_FOUND");
        }

        if ("TERMINATED".equals(employee.getStatus())) {
            return new ServiceResponse(false,
                    "Employee " + employeeId + " is already terminated.", "ERR_ALREADY_TERMINATED");
        }

        if (reason == null || reason.trim().isEmpty()) {
            return new ServiceResponse(false,
                    "Termination reason is required.", "ERR_MISSING_REASON");
        }

        if (terminationType == null || terminationType.trim().isEmpty()) {
            return new ServiceResponse(false,
                    "Termination type is required (VOLUNTARY, INVOLUNTARY, LAYOFF, RETIREMENT).",
                    "ERR_MISSING_TYPE");
        }

        String validTypes = "VOLUNTARY,INVOLUNTARY,LAYOFF,RETIREMENT";
        if (!validTypes.contains(terminationType.toUpperCase())) {
            return new ServiceResponse(false,
                    "Invalid termination type. Must be: VOLUNTARY, INVOLUNTARY, LAYOFF, or RETIREMENT.",
                    "ERR_INVALID_TYPE");
        }

        if (processedBy == null || processedBy.trim().isEmpty()) {
            return new ServiceResponse(false,
                    "Processor name is required.", "ERR_MISSING_PROCESSOR");
        }

        String previousStatus = employee.getStatus();
        employee.setStatus("TERMINATED");
        employee.setTerminationDate(terminationDate != null ? terminationDate :
                new SimpleDateFormat("yyyy-MM-dd").format(new Date()));

        System.out.println("[HR Service] TERMINATION PROCESSED:");
        System.out.println("  Employee: " + employee.getFirstName() + " " + employee.getLastName() +
                " (ID: " + employeeId + ")");
        System.out.println("  Type: " + terminationType);
        System.out.println("  Reason: " + reason);
        System.out.println("  Processed By: " + processedBy);
        System.out.println("  Eligible for Rehire: " + eligibleForRehire);
        if (exitInterviewNotes != null && !exitInterviewNotes.trim().isEmpty()) {
            System.out.println("  Exit Interview Notes: " + exitInterviewNotes);
        }

        return new ServiceResponse(true,
                "Employee " + employee.getFirstName() + " " + employee.getLastName() +
                " (ID: " + employeeId + ") has been terminated. Type: " + terminationType +
                ", Effective: " + employee.getTerminationDate() +
                ", Eligible for Rehire: " + (eligibleForRehire ? "Yes" : "No"));
    }

    @WebMethod(operationName = "reinstateEmployee")
    public ServiceResponse reinstateEmployee(
            @WebParam(name = "employeeId") int employeeId,
            @WebParam(name = "reason") String reason,
            @WebParam(name = "approvedBy") String approvedBy) {

        Employee employee = employeeDatabase.get(employeeId);

        if (employee == null) {
            return new ServiceResponse(false,
                    "Employee with ID " + employeeId + " not found.", "ERR_NOT_FOUND");
        }

        if ("ACTIVE".equals(employee.getStatus())) {
            return new ServiceResponse(false,
                    "Employee " + employeeId + " is already active.", "ERR_ALREADY_ACTIVE");
        }

        employee.setStatus("ACTIVE");
        employee.setTerminationDate(null);

        System.out.println("[HR Service] Employee " + employeeId + " reinstated by " +
                approvedBy + ". Reason: " + reason);

        return new ServiceResponse(true,
                "Employee " + employee.getFirstName() + " " + employee.getLastName() +
                " has been reinstated successfully. Approved by: " + approvedBy);
    }

    @WebMethod(operationName = "getTerminatedEmployees")
    public String getTerminatedEmployees() {
        StringBuilder sb = new StringBuilder();
        sb.append("=== Terminated Employees ===\n");

        int count = 0;
        for (Employee emp : employeeDatabase.values()) {
            if ("TERMINATED".equals(emp.getStatus())) {
                sb.append("ID: ").append(emp.getEmployeeId())
                  .append(" | Name: ").append(emp.getFirstName()).append(" ").append(emp.getLastName())
                  .append(" | Dept: ").append(emp.getDepartment())
                  .append(" | Position: ").append(emp.getPosition())
                  .append(" | Termination Date: ").append(emp.getTerminationDate())
                  .append("\n");
                count++;
            }
        }

        if (count == 0) {
            return "No terminated employees found.";
        }

        sb.append("Total Terminated: ").append(count);
        return sb.toString();
    }

    // ==================== Employee Update Operations ====================

    @WebMethod(operationName = "updateEmployeeDepartment")
    public ServiceResponse updateEmployeeDepartment(
            @WebParam(name = "employeeId") int employeeId,
            @WebParam(name = "newDepartment") String newDepartment,
            @WebParam(name = "approvedBy") String approvedBy) {

        Employee employee = employeeDatabase.get(employeeId);

        if (employee == null) {
            return new ServiceResponse(false, "Employee not found.", "ERR_NOT_FOUND");
        }

        if (!"ACTIVE".equals(employee.getStatus())) {
            return new ServiceResponse(false,
                    "Cannot update department for non-active employee.", "ERR_INACTIVE_EMPLOYEE");
        }

        String oldDepartment = employee.getDepartment();
        employee.setDepartment(newDepartment);

        System.out.println("[HR Service] Department transfer: Employee " + employeeId +
                " from " + oldDepartment + " to " + newDepartment);

        return new ServiceResponse(true,
                "Employee " + employee.getFirstName() + " " + employee.getLastName() +
                " transferred from " + oldDepartment + " to " + newDepartment);
    }

