    @WebMethod(operationName = "promoteEmployee")
    public ServiceResponse promoteEmployee(
            @WebParam(name = "employeeId") int employeeId,
            @WebParam(name = "newPosition") String newPosition,
            @WebParam(name = "salaryIncreasePercent") double salaryIncreasePercent,
            @WebParam(name = "approvedBy") String approvedBy) {

        Employee employee = employeeDatabase.get(employeeId);

        if (employee == null) {
            return new ServiceResponse(false, "Employee not found.", "ERR_NOT_FOUND");
        }

        if (!"ACTIVE".equals(employee.getStatus())) {
            return new ServiceResponse(false,
                    "Cannot promote non-active employee.", "ERR_INACTIVE_EMPLOYEE");
        }

        String oldPosition = employee.getPosition();
        double oldSalary = employee.getSalary();
        double newSalary = oldSalary * (1 + salaryIncreasePercent / 100);

        employee.setPosition(newPosition);
        employee.setSalary(newSalary);

        String effectiveDate = new SimpleDateFormat("yyyy-MM-dd").format(new Date());
        SalaryHistoryEntry historyEntry = new SalaryHistoryEntry(
                employeeId, oldSalary, newSalary,
                "Promotion: " + oldPosition + " -> " + newPosition,
                effectiveDate, approvedBy);
        salaryHistory.add(historyEntry);

        System.out.println("[HR Service] PROMOTION: Employee " + employeeId +
                " promoted from " + oldPosition + " to " + newPosition +
                " with " + salaryIncreasePercent + "% salary increase");

        return new ServiceResponse(true,
                "Employee " + employee.getFirstName() + " " + employee.getLastName() +
                " promoted from " + oldPosition + " to " + newPosition +
                ". Salary: $" + String.format("%.2f", oldSalary) + " -> $" +
                String.format("%.2f", newSalary) +
                " (+" + String.format("%.1f", salaryIncreasePercent) + "%)");
    }

    // ==================== Reporting Operations ====================

    @WebMethod(operationName = "getHeadcount")
    public String getHeadcount() {
        int active = 0, terminated = 0, onLeave = 0, total = employeeDatabase.size();

        for (Employee emp : employeeDatabase.values()) {
            switch (emp.getStatus()) {
                case "ACTIVE": active++; break;
                case "TERMINATED": terminated++; break;
                case "ON_LEAVE": onLeave++; break;
            }
        }

        return "=== Headcount Report ===\n" +
               "Active: " + active + "\n" +
               "Terminated: " + terminated + "\n" +
               "On Leave: " + onLeave + "\n" +
               "Total Records: " + total;
    }

    @WebMethod(operationName = "getCompanySalaryReport")
    public String getCompanySalaryReport() {
        StringBuilder sb = new StringBuilder();
        sb.append("=== Company Salary Report ===\n");

        Map<String, double[]> deptStats = new HashMap<>();

        for (Employee emp : employeeDatabase.values()) {
            if (!"ACTIVE".equals(emp.getStatus())) continue;

            String dept = emp.getDepartment();
            double[] stats = deptStats.computeIfAbsent(dept, k -> new double[]{0, 0, Double.MAX_VALUE, 0});
            stats[0] += emp.getSalary(); // total
            stats[1]++; // count
            stats[2] = Math.min(stats[2], emp.getSalary()); // min
            stats[3] = Math.max(stats[3], emp.getSalary()); // max
        }

        double grandTotal = 0;
        int grandCount = 0;

        for (Map.Entry<String, double[]> entry : deptStats.entrySet()) {
            double[] stats = entry.getValue();
            sb.append("Department: ").append(entry.getKey()).append("\n");
            sb.append("  Employees: ").append((int) stats[1]).append("\n");
            sb.append("  Total Budget: $").append(String.format("%.2f", stats[0])).append("\n");
            sb.append("  Average Salary: $").append(String.format("%.2f", stats[0] / stats[1])).append("\n");
            sb.append("  Min: $").append(String.format("%.2f", stats[2])).append("\n");
            sb.append("  Max: $").append(String.format("%.2f", stats[3])).append("\n");
            sb.append("---\n");
            grandTotal += stats[0];
            grandCount += (int) stats[1];
        }

        sb.append("COMPANY TOTAL:\n");
        sb.append("  Total Employees (Active): ").append(grandCount).append("\n");
        sb.append("  Total Salary Budget: $").append(String.format("%.2f", grandTotal)).append("\n");
        if (grandCount > 0) {
            sb.append("  Company Average Salary: $").append(String.format("%.2f", grandTotal / grandCount)).append("\n");
        }

        return sb.toString();
    }

